public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText);
}

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and selects the most representative ones.
/// </summary>
public class ExtractiveSummarizer : IDocumentSummarizer
{
    private const int MaxSummarySentences = 3;

    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "its",
        "this", "that", "from", "as", "be", "been", "being", "have", "has",
        "had", "do", "does", "did", "will", "would", "could", "should",
        "may", "might", "not", "no", "so", "if", "then", "than", "too",
        "very", "can", "just", "about", "into", "over", "after", "before",
        "between", "each", "all", "both", "such", "through", "during",
        "up", "down", "out", "off", "above", "below", "he", "she", "they",
        "we", "you", "i", "me", "him", "her", "us", "them", "my", "your",
        "his", "our", "their", "which", "who", "whom", "what", "where",
        "when", "how", "there", "here", "also", "more", "some", "any",
        "other", "only", "while", "because", "until", "although"
    };

    public string Summarize(string documentText)
    {
        var sentences = SplitSentences(documentText);
        if (sentences.Count <= MaxSummarySentences)
            return documentText.Trim();

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(MaxSummarySentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        var sentences = new List<string>();
        int start = 0;

        for (int i = 0; i < text.Length; i++)
        {
            if (text[i] is '.' or '!' or '?')
            {
                // Consume trailing punctuation (e.g. "..." or "?!")
                while (i + 1 < text.Length && text[i + 1] is '.' or '!' or '?')
                    i++;

                var sentence = text[start..(i + 1)].Trim();
                if (sentence.Length > 0)
                    sentences.Add(sentence);
                start = i + 1;
            }
        }

        // Remaining text without terminal punctuation
        if (start < text.Length)
        {
            var remaining = text[start..].Trim();
            if (remaining.Length > 0)
                sentences.Add(remaining);
        }

        return sentences;
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (!StopWords.Contains(word))
                    frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
            }
        }

        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = GetWords(sentence).ToList();
        if (words.Count == 0)
            return 0;

        double score = words
            .Where(w => !StopWords.Contains(w))
            .Sum(w => wordFrequencies.GetValueOrDefault(w));

        // Normalize by word count to avoid bias toward long sentences
        return score / words.Count;
    }

    private static IEnumerable<string> GetWords(string text) =>
        text.Split([' ', '\t', '\n', '\r', ',', ';', ':', '"', '\'', '(', ')', '[', ']', '{', '}'],
                StringSplitOptions.RemoveEmptyEntries)
            .Select(w => w.Trim('.', '!', '?'))
            .Where(w => w.Length > 0);
}

using DocSummary.Models;
